func:
// Масштабирование: ПЛК ОВЕН — AI1 диапазон 0-4000 единиц = 4-20 мА = 0-2000 ppm CO2
// Регистры: [0]=CO2(0-4000), [1]=T(*0.1 °C), [2]=RH(*0.1 %)
const regs = msg.payload;
if (!Array.isArray(regs) || regs.length < 3) return null;

msg.sensor_id = 1;
msg.co2_1 = Math.round(regs[0] * 2000 / 4000);  // 0-4000 → 0-2000 ppm
msg.temp_1 = regs[1] / 10;                         // *0.1 °C
msg.rh_1   = regs[2] / 10;                         // *0.1 %
return msg;

// AI2: регистры 3-5 (CO2, T, RH) — аналогично датчику №1
const regs = msg.payload;
if (!Array.isArray(regs) || regs.length < 3) return null;

msg.sensor_id = 2;
msg.co2_2 = Math.round(regs[0] * 2000 / 4000);
msg.temp_2 = regs[1] / 10;
msg.rh_2   = regs[2] / 10;
return msg;

// Объединяем данные двух датчиков, берём максимум CO2 (консервативная стратегия)
const s1 = msg.payload[1] || {};
const s2 = msg.payload[2] || {};

const co2_1 = s1.co2_1 || 450;
const co2_2 = s2.co2_2 || 450;
const co2_max = Math.max(co2_1, co2_2);

const temp = ((s1.temp_1 || 20) + (s2.temp_2 || 20)) / 2;
const rh   = ((s1.rh_1 || 45)  + (s2.rh_2 || 45))   / 2;

// Определяем текущий режим по расписанию
const hour = new Date().getHours();
let mode = global.get('manual_mode') || 'NIGHT';
if (!global.get('manual_mode')) {
    if (hour >= 11 && hour <= 23) {
        const prestart = [{s:11,e:12},{s:14,e:15},{s:18,e:19}];
        const sessions = [{s:12,e:14},{s:15,e:18},{s:19,e:22}];
        const interms  = [{s:14,e:15},{s:18,e:19},{s:22,e:23}];
        mode = 'SESSION';
        for (const p of prestart) { if (hour >= p.s && hour < p.e) { mode = 'PRESTART'; break; } }
        if (mode === 'SESSION') {
            for (const i of interms) { if (hour >= i.s && hour < i.e) { mode = 'INTERMISSION'; break; } }
        }
    }
}

msg.payload = {
    co2_1, co2_2,
    co2:  co2_max,
    temp: Math.round(temp * 10) / 10,
    rh:   Math.round(rh * 10) / 10,
    mode
};
return msg;

// ============================================================
// DCV Controller — алгоритм управления вентиляцией по CO2
// ВКР: Повышение энергоэффективности кинозала, ИТМО 2026
// ============================================================

const co2  = msg.payload.co2;
const mode = msg.payload.mode || 'SESSION';

// --- Уставки (ppm) по ГОСТ 30494-2011 ---
const CO2_BG    = 500;   // фоновый уровень (пустой зал)
const CO2_SET   = 700;   // нормативная уставка DCV
const CO2_WARN  = 1200;  // предупредительный порог
const CO2_ALARM = 1400;  // аварийный порог

// --- Пределы производительности вентиляторов (%) ---
const FAN_NIGHT  = 10;
const FAN_MIN    = 30;
const FAN_INTERM = 40;
const FAN_NOM    = 100;

// --- Параметры вентустановки ---
const Q_NOM_M3H = 4050;
const P_NOM_KW  = 1.97;

let freq_pct = FAN_MIN;
let alarm = 0, warning = 0;
let status_text = '';

switch (mode) {
    case 'NIGHT':
        freq_pct = FAN_NIGHT;
        status_text = 'Ночной режим';
        break;
    case 'PRESTART':
        freq_pct = FAN_NOM;
        status_text = 'Предпуск (продувка зала)';
        break;
    case 'INTERMISSION':
        freq_pct = FAN_INTERM;
        status_text = 'Межсеансовый перерыв';
        break;
    case 'SESSION':
    default:
        if (co2 >= CO2_ALARM) {
            freq_pct = FAN_NOM; alarm = 1; warning = 1;
            status_text = 'АВАРИЯ: CO2 > ' + CO2_ALARM + ' ppm!';
        } else if (co2 >= CO2_WARN) {
            freq_pct = FAN_NOM; warning = 1;
            status_text = 'Предупреждение: CO2 > ' + CO2_WARN + ' ppm';
        } else if (co2 <= CO2_BG) {
            freq_pct = FAN_MIN;
            status_text = 'Дежурный режим';
        } else {
            // Пропорциональное управление CO2_BG..CO2_SET → FAN_MIN..FAN_NOM
            freq_pct = FAN_MIN + (FAN_NOM - FAN_MIN) * (co2 - CO2_BG) / (CO2_SET - CO2_BG);
            freq_pct = Math.round(Math.min(FAN_NOM, Math.max(FAN_MIN, freq_pct)));
            status_text = 'DCV-управление активно';
        }
        break;
}

const freq_hz  = Math.round(50 * freq_pct / 100);
const flow_m3h = Math.round(Q_NOM_M3H * freq_pct / 100);
const p_kw     = P_NOM_KW * Math.pow(freq_pct / 100, 3);
const savings_w = Math.round((P_NOM_KW - p_kw) * 1000);

msg.payload = {
    co2, co2_1: msg.payload.co2_1, co2_2: msg.payload.co2_2,
    temp: msg.payload.temp, rh: msg.payload.rh, mode,
    freq_pct, freq_hz, flow_m3h,
    power_kw:    Math.round(p_kw * 1000) / 1000,
    power_base:  P_NOM_KW,
    savings_w,
    savings_pct: Math.round((1 - Math.pow(freq_pct / 100, 3)) * 100),
    warning, alarm, status: status_text,
    ts: new Date().toISOString()
};

const outputs = [null, null];
outputs[alarm ? 1 : 0] = msg;
return outputs;

// Формирование Modbus-запроса на запись уставки частоты ЧП приточного вентилятора
// ПЛК ОВЕН: Holding Register HR10, unit=1
// Масштаб: 0-1000 = 0-100% производительности (0-50 Гц)
const freq_raw = Math.round(msg.payload.freq_pct * 10); // 30% → 300, 100% → 1000
msg.payload = { value: [freq_raw], fc: 16, unitid: 1, address: 10, quantity: 1 };
return msg;

// Holding Register HR11, unit=1 — уставка ЧП вытяжного вентилятора
// Поддерживаем баланс: приток = вытяжка (равные уставки частоты)
const freq_raw = Math.round(msg.payload.freq_pct * 10);
msg.payload = { value: [freq_raw], fc: 16, unitid: 1, address: 11, quantity: 1 };
return msg;

const d = msg.payload;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const timeStr = now.toTimeString().split(' ')[0];

const row = [
    `${dateStr} ${timeStr}`,
    d.co2_1, d.co2_2, d.co2,
    d.temp, d.rh, d.mode,
    d.freq_pct, d.flow_m3h,
    d.power_kw, d.savings_pct
].join(',');

msg.filename = `/home/node-red/logs/dcv_${dateStr}.csv`;
msg.payload  = row + '\n';
msg.flags    = { append: true };
return msg;

const d = msg.payload;
const level = d.alarm ? 'АВАРИЯ' : 'ПРЕДУПРЕЖДЕНИЕ';
node.warn(`${level}: CO2=${d.co2} ppm. Вентиляция ${d.freq_pct}%.`);

msg.topic = `${level} CO2 — Кинозал`;
msg.payload = {
    type: d.alarm ? 'ALARM' : 'WARNING',
    message: `${level}: CO2 = ${d.co2} ppm\nВентиляция: ${d.freq_pct}% (${d.flow_m3h} м³/ч)\n` +
             `Время: ${d.ts}\nОбъект: Кинозал, Ярославский пр. 55`,
    co2: d.co2, ts: d.ts
};
return msg;

if (msg.payload === 'AUTO') {
    global.set('manual_mode', null);
    msg.payload = { status: 'Режим: АВТО (по расписанию)' };
} else {
    global.set('manual_mode', msg.payload);
    msg.payload = { status: `Режим принудительно: ${msg.payload}` };
}
return msg;

const d = msg.payload;
const dt_h = 30 / 3600;
const delta_e = (d.power_base - d.power_kw) * dt_h;

let daily = context.get('daily_savings') || 0;
daily += delta_e;
context.set('daily_savings', daily);

const now = new Date();
if (now.getHours() === 0 && now.getMinutes() < 1) context.set('daily_savings', 0);

msg.payload = {
    daily_savings_kwh: Math.round(daily * 100) / 100,
    daily_savings_rub: Math.round(daily * 8.64 * 100) / 100,
    current_power_kw:  d.power_kw,
    savings_pct:       d.savings_pct
};
return msg;
